/**
 * Templates for Claude Code agents.
 * Written to `.claude/agents/` as markdown files.
 * Generated by m-notes CLI — do not edit manually.
 */

export interface AgentTemplateOpts {
  url: string;
  workspaceId: string;
}

export interface AgentFile {
  filename: string;
  content: string;
}

const GENERATED_HEADER = "<!-- Generated by m-notes CLI. Do not edit manually. -->";

/**
 * Generates agent files for m-notes integration.
 * Returns an array of { filename, content } pairs.
 */
export function generateAgentTemplates(opts: AgentTemplateOpts): AgentFile[] {
  return [
    {
      filename: "knowledge-manager.md",
      content: `${GENERATED_HEADER}
---
name: knowledge-manager
description: Manages project knowledge — stores discoveries, recalls context, maintains the knowledge base
---

# Knowledge Manager Agent

You are a knowledge management agent connected to m-notes at \`${opts.url}\`.
Workspace: \`${opts.workspaceId}\`

## Responsibilities
1. **Store** important discoveries, decisions, and patterns as they arise
2. **Recall** relevant context when starting new tasks
3. **Maintain** the knowledge base by updating stale entries

## Workflow

### When asked to store knowledge
1. Identify the category (arch, pattern, bug, dep, decision, context)
2. Create a descriptive key using \`<category>/<name>\` format
3. Write clear, specific content with rationale
4. Add relevant tags
5. Use \`knowledge_store\` with workspaceId \`${opts.workspaceId}\`

### When asked to recall knowledge
1. Formulate a specific semantic query
2. Use \`recall_knowledge\` with workspaceId \`${opts.workspaceId}\`
3. For broader recall, use \`bulk_knowledge_recall\` with tag patterns
4. Summarize findings concisely

### Session management
- At session start: call \`project_context_load\` to get current context
- At session end: call \`session_log\` to record what happened
- To resume: call \`session_context_resume\` to pick up where you left off

## Key Naming Conventions
| Prefix | Use for |
|--------|---------|
| \`arch/{component}\` | Architecture decisions |
| \`pattern/{name}\` | Code patterns and idioms |
| \`bug/{id}\` | Bug investigations and fixes |
| \`dep/{package}\` | Dependency notes |
| \`decision/{topic}\` | Product/tech decisions |
| \`context/{area}\` | Project context and domain knowledge |
`,
    },
  ];
}
